            py: "# Step 1 â load, set, render.\n#\n# The smallest meaningful FragmentColor pipeline: a Renderer creates a\n# Target wrapped around a window, and a Shader fetched from a URL exposes\n# one settable uniform. We cycle the `color` uniform every frame to show\n# that the same shader handle is the surface for live updates â no\n# rebuild, no rebind.\n#\n# Outside the `setup` and `frame` regions below is the tiny winit\n# bootstrap that opens a window, drives the redraw loop, and blocks on\n# the OS event loop. It's identical in every step of this tutorial; the\n# FragmentColor API surface lives entirely inside the two regions.\n\nfrom fragmentcolor import App, Renderer, SetupResult, Shader, call, run\nuse std.sync.{Arc, OnceLock}\nuse std.time.Instant\nuse winit.dpi.PhysicalSize\nuse winit.window.Window\n\n# #region: setup\nasync fn setup(app: App, windows: Vec<Arc<Window>>) -> SetupResult {\nshader = Shader(\"https://fragmentcolor.org/triangle.wgsl\")\n    shader.set(\"color\", [0.95, 0.30, 0.42, 1.0])\n    app.add(\"shader.main\", shader)\n\n    for win in windows {\ntarget = app.get_renderer().create_target(win.clone())\n        app.add_target(win.id(), target)\n    }\n    Ok(())\n}\n# #endregion: setup\n\nfn resize(app: App, new_size: PhysicalSize<u32>) {\n    app.resize([new_size.width, new_size.height])\n}\n\n# #region: frame\nfn draw(app: App) {\n    static START: OnceLock<Instant> = OnceLock()\ntime = START.get_or_init(Instant.now).elapsed().as_secs_f32()\n\n    if let Some(shader) = app.get.<Shader>(\"shader.main\") {\nr = 0.5 + 0.45 * (time * 0.7).sin()\ng = 0.5 + 0.45 * (time * 0.5 + 1.7).cos()\nb = 0.5 + 0.45 * (time * 0.9 + 3.1).sin()\n_ = shader.set(\"color\", [r, g, b, 1.0])\n\nid = app.primary_window_id()\nrenderer = app.get_renderer()\n_ = app.with_target(id, |target| renderer.render(shader, target))\n    }\n}\n# #endregion: frame\n\nfn main() -> Result<(), Box<dyn std.error.Error + Send + Sync>> {\nrenderer = Renderer()\napp = App(renderer)\n    app.on_start(call!(setup))\n        .on_resize(resize)\n        .on_redraw_requested(draw)\n    run(mut app)\n    Ok(())\n}",
            swift: "// Step 1 â load, set, render.\n//\n// The smallest meaningful FragmentColor pipeline: a Renderer creates a\n// Target wrapped around a window, and a Shader fetched from a URL exposes\n// one settable uniform. We cycle the \"\"\"color\"\"\" uniform every frame to show\n// that the same shader handle is the surface for live updates â no\n// rebuild, no rebind.\n//\n// Outside the \"\"\"setup\"\"\" and \"\"\"frame\"\"\" regions below is the tiny winit\n// bootstrap that opens a window, drives the redraw loop, and blocks on\n// the OS event loop. It's identical in every step of this tutorial; the\n// FragmentColor API surface lives entirely inside the two regions.\n\nimport FragmentColor\nuse std.sync.{Arc, OnceLock}\nuse std.time.Instant\nuse winit.dpi.PhysicalSize\nuse winit.window.Window\n\n// #region: setup\nasync fn setup(app: App, windows: Vec<Arc<Window>>) -> SetupResult {\nlet shader = Shader(\"https://fragmentcolor.org/triangle.wgsl\")\n    shader.set(\"color\", [0.95, 0.30, 0.42, 1.0])\n    app.add(\"shader.main\", shader)\n\n    for win in windows {\nlet target = try await app.getRenderer().createTarget(win.clone())\n        app.addTarget(win.id(), target)\n    }\n    Ok(())\n}\n// #endregion: setup\n\nfn resize(app: App, new_size: PhysicalSize<u32>) {\n    app.resize([new_size.width, new_size.height])\n}\n\n// #region: frame\nfn draw(app: App) {\n    static START: OnceLock<Instant> = OnceLock.new()\nlet time = START.getOrInit(Instant.now).elapsed().asSecsF32()\n\n    if let Some(shader) = app.get.<Shader>(\"shader.main\") {\nlet r = 0.5 + 0.45 * (time * 0.7).sin()\nlet g = 0.5 + 0.45 * (time * 0.5 + 1.7).cos()\nlet b = 0.5 + 0.45 * (time * 0.9 + 3.1).sin()\nlet _ = shader.set(\"color\", [r, g, b, 1.0])\n\nlet id = app.primaryWindowId()\nlet renderer = app.getRenderer()\nlet _ = app.withTarget(id, |target| renderer.render(shader, target))\n    }\n}\n// #endregion: frame\n\nfn main() -> Result<(), Box<dyn std.error.Error + Send + Sync>> {\nlet renderer = Renderer()\nlet app = App(renderer)\n    app.onStart(call!(setup))\n        .onResize(resize)\n        .onRedrawRequested(draw)\n    run(mut app)\n    Ok(())\n}",
