                rust: "async fn setup(app: &App, windows: Vec<Arc<Window>>) -> SetupResult {\n    // Particle shader and mesh — same as step 3.\n    let particle_shader = Shader::new(PARTICLE_WGSL)?;\n    particle_shader.set(\"time\", 0.0_f32)?;\n\n    let mesh = Mesh::new();\n    mesh.add_vertices([\n        Vertex::new([-0.6, -0.5, 0.0]).set(\"color\", [0.95, 0.30, 0.42]),\n        Vertex::new([0.6, -0.5, 0.0]).set(\"color\", [0.30, 0.85, 0.55]),\n        Vertex::new([0.0, 0.7, 0.0]).set(\"color\", [0.30, 0.55, 0.95]),\n    ]);\n\n    let mut instances = Vec::with_capacity(PARTICLE_COUNT);\n    for _ in 0..PARTICLE_COUNT {\n        let cx = fastrand::f32() * 1.8 - 0.9;\n        let cy = fastrand::f32() * 1.8 - 0.9;\n        let phase = fastrand::f32() * std::f32::consts::TAU;\n        let tint = [\n            0.6 + fastrand::f32() * 0.4,\n            0.6 + fastrand::f32() * 0.4,\n            0.6 + fastrand::f32() * 0.4,\n        ];\n        instances.push(\n            Instance::new()\n                .set(\"center\", [cx, cy])\n                .set(\"phase\", phase)\n                .set(\"tint\", tint),\n        );\n    }\n    mesh.add_instances(instances);\n\n    // Intermediate texture target — the bridge between the two passes.\n    // The postfx shader holds a Texture handle pointing at the same GPU\n    // resource, and the renderer's texture pool retains an Arc to it as\n    // soon as `intermediate.texture()` is called, so the underlying GPU\n    // texture stays alive after this function returns.\n    let intermediate = app\n        .get_renderer()\n        .create_texture_target([SCENE_SIZE, SCENE_SIZE])\n        .await?;\n    let scene_texture = intermediate.texture();\n\n    // Postfx shader composed from two registry slugs and a main source.\n    // `postfx/vignette` and `postfx/film_grain` are pure WGSL helper\n    // functions; Shader::new concatenates them with our main shader and\n    // hands the merged source to naga for validation.\n    let postfx_shader = Shader::new([\"postfx/vignette\", \"postfx/film_grain\", POSTFX_MAIN_WGSL])?;\n    postfx_shader.set(\"scene\", &scene_texture)?;\n    postfx_shader.set(\"time\", 0.0_f32)?;\n\n    // Pass 1: render the particles INTO the intermediate texture.\n    let particle_pass = Pass::from_shader(\"particles\", &particle_shader);\n    particle_pass.add_mesh(&mesh)?;\n    particle_pass.add_target(&intermediate)?;\n    particle_pass.set_clear_color([0.04, 0.05, 0.08, 1.0]);\n\n    // Pass 2: sample the intermediate, apply postfx, render to the canvas.\n    let postfx_pass = Pass::from_shader(\"postfx\", &postfx_shader);\n    postfx_pass.require(&particle_pass)?;\n\n    app.add(\"shader.particle\", particle_shader);\n    app.add(\"shader.postfx\", postfx_shader);\n    app.add(\"pass.particle\", particle_pass);\n    app.add(\"pass.postfx\", postfx_pass);\n    app.add(\"mesh.main\", mesh);\n\n    for win in windows {\n        let target = app.get_renderer().create_target(win.clone()).await?;\n        app.add_target(win.id(), target);\n    }\n    Ok(())\n}",
                js: "export async function setup(renderer, _target) {\n    // Particle shader and mesh — same as step 3.\n    const particleShader = new Shader(PARTICLE_WGSL);\n    particleShader.set(\"time\", 0.0);\n\n    const mesh = new Mesh();\n    mesh.addVertices([\n        new Vertex([-0.6, -0.5, 0.0]).set(\"color\", [0.95, 0.30, 0.42]),\n        new Vertex([ 0.6, -0.5, 0.0]).set(\"color\", [0.30, 0.85, 0.55]),\n        new Vertex([ 0.0,  0.7, 0.0]).set(\"color\", [0.30, 0.55, 0.95]),\n    ]);\n\n    const TAU = Math.PI * 2;\n    const instances = [];\n    for (let i = 0; i < PARTICLE_COUNT; i++) {\n        instances.push(\n            new Instance()\n                .set(\"center\", [Math.random() * 1.8 - 0.9, Math.random() * 1.8 - 0.9])\n                .set(\"phase\", Math.random() * TAU)\n                .set(\"tint\", [\n                    0.6 + Math.random() * 0.4,\n                    0.6 + Math.random() * 0.4,\n                    0.6 + Math.random() * 0.4,\n                ]),\n        );\n    }\n    mesh.addInstances(instances);\n\n    // Intermediate texture target — the bridge between the two passes.\n    const intermediate = await renderer.createTextureTarget([SCENE_SIZE, SCENE_SIZE]);\n    const sceneTexture = intermediate.texture();\n\n    // Postfx shader composed from two registry slugs and a main source.\n    // Shader.fetch is the async builder — needed because slugs/URLs require fetching.\n    const postfxShader = await Shader.fetch([\n        \"postfx/vignette\",\n        \"postfx/film_grain\",\n        POSTFX_MAIN_WGSL,\n    ]);\n    postfxShader.set(\"scene\", sceneTexture);\n    postfxShader.set(\"time\", 0.0);\n\n    // Pass 1: render the particles INTO the intermediate texture.\n    const particlePass = Pass.fromShader(\"particles\", particleShader);\n    particlePass.addMesh(mesh);\n    particlePass.addTarget(intermediate);\n    particlePass.setClearColor([0.04, 0.05, 0.08, 1.0]);\n\n    // Pass 2: sample the intermediate, apply postfx, render to the canvas.\n    const postfxPass = Pass.fromShader(\"postfx\", postfxShader);\n\n    return {\n        particleShader,\n        postfxShader,\n        particlePass,\n        postfxPass,\n        mesh,\n        intermediate,\n    };\n}",
                py: "async fn setup(app: App, windows: Vec<Arc<Window>>) -> SetupResult {\n# Particle shader and mesh â same as step 3.\nparticle_shader = Shader(PARTICLE_WGSL)\n    particle_shader.set(\"time\", 0.0_)\n\nmesh = Mesh()\n    mesh.add_vertices([\n        Vertex([-0.6, -0.5, 0.0]).set(\"color\", [0.95, 0.30, 0.42]),\n        Vertex([0.6, -0.5, 0.0]).set(\"color\", [0.30, 0.85, 0.55]),\n        Vertex([0.0, 0.7, 0.0]).set(\"color\", [0.30, 0.55, 0.95]),\n    ])\n\ninstances = Vec.with_capacity(PARTICLE_COUNT)\n    for _ in 0..PARTICLE_COUNT {\ncx = fastrand.f32() * 1.8 - 0.9\ncy = fastrand.f32() * 1.8 - 0.9\nphase = fastrand.f32() * std.f32.consts.TAU\ntint = [\n            0.6 + fastrand.f32() * 0.4,\n            0.6 + fastrand.f32() * 0.4,\n            0.6 + fastrand.f32() * 0.4,\n        ]\n        instances.push(\n            Instance()\n                .set(\"center\", [cx, cy])\n                .set(\"phase\", phase).set(\"tint\", tint),\n        )\n    }\n    mesh.add_instances(instances)\n\n# Intermediate texture target â the bridge between the two passes.\n# The postfx shader holds a Texture handle pointing at the same GPU\n# resource, and the renderer's texture pool retains an Arc to it as\n# soon as `intermediate.texture()` is called, so the underlying GPU\n# texture stays alive after this function returns.\nintermediate = app.get_renderer().create_texture_target([SCENE_SIZE, SCENE_SIZE])\nscene_texture = intermediate.texture()\n\n# Postfx shader composed from two registry slugs and a main source.\n# `postfx/vignette` and `postfx/film_grain` are pure WGSL helper\n# functions; Shader.new concatenates them with our main shader and\n# hands the merged source to naga for validation.\npostfx_shader = Shader([\"postfx/vignette\", \"postfx/film_grain\", POSTFX_MAIN_WGSL])\n    postfx_shader.set(\"scene\", scene_texture)\n    postfx_shader.set(\"time\", 0.0_)\n\n# Pass 1: render the particles INTO the intermediate texture.\nparticle_pass = Pass(\"particles\"); particle_pass.add_shader(particle_shader)\n    particle_pass.add_mesh(mesh)\n    particle_pass.add_target(intermediate)\n    particle_pass.set_clear_color([0.04, 0.05, 0.08, 1.0])\n\n# Pass 2: sample the intermediate, apply postfx, render to the canvas.\npostfx_pass = Pass(\"postfx\"); postfx_pass.add_shader(postfx_shader)\n    postfx_pass.require(particle_pass)\n\n    app.add(\"shader.particle\", particle_shader)\n    app.add(\"shader.postfx\", postfx_shader)\n    app.add(\"pass.particle\", particle_pass)\n    app.add(\"pass.postfx\", postfx_pass)\n    app.add(\"mesh.main\", mesh)\n\n    for win in windows {\ntarget = app.get_renderer().create_target(win.clone())\n        app.add_target(win.id(), target)\n    }\n    Ok(())\n}",
