                kotlin: "async fn setup(app: App, windows: Vec<Arc<Window>>) -> SetupResult {\n    // Particle shader and mesh â same as step 3.\nval particle_shader = Shader(PARTICLE_WGSL)\n    particle_shader.set(\"time\", 0.0)\n\nval mesh = Mesh()\n    mesh.addVertices([\n        Vertex.new(arrayOf(-0.6, -0.5, 0.0)).set(\"color\", arrayOf(0.95, 0.30, 0.42)),\n        Vertex.new(arrayOf(0.6, -0.5, 0.0)).set(\"color\", arrayOf(0.30, 0.85, 0.55)),\n        Vertex.new(arrayOf(0.0, 0.7, 0.0)).set(\"color\", arrayOf(0.30, 0.55, 0.95)),\n    ])\n\nval instances = Vec.withCapacity(PARTICLE_COUNT)\n    for _ in 0..PARTICLECOUNT {\nval cx = fastrand.f32() * 1.8 - 0.9\nval cy = fastrand.f32() * 1.8 - 0.9\nval phase = fastrand.f32() * std.f32.consts.TAU\nval tint = [\n            0.6 + fastrand.f32() * 0.4,\n            0.6 + fastrand.f32() * 0.4,\n            0.6 + fastrand.f32() * 0.4,\n        ]\n        instances.push(\n            Instance.new()\n                .set(\"center\", arrayOf(cx, cy))\n                .set(\"phase\", phase).set(\"tint\", tint),\n        )\n    }\n    mesh.addInstances(instances)\n\n    // Intermediate texture target â the bridge between the two passes.\n    // The postfx shader holds a Texture handle pointing at the same GPU\n    // resource, and the renderer's texture pool retains an Arc to it as\n    // soon as \"\"\"intermediate.texture()\"\"\" is called, so the underlying GPU\n    // texture stays alive after this function returns.\nval intermediate = app.getRenderer().createTextureTarget(arrayOf(SCENE_SIZE, SCENE_SIZE))\nval scene_texture = intermediate.texture()\n\n    // Postfx shader composed from two registry slugs and a main source.\n    // \"\"\"postfx/vignette\"\"\" and \"\"\"postfx/film_grain\"\"\" are pure WGSL helper\n    // functions; Shader.concatenates them with our main shader and\n    // hands the merged source to naga for validation.\nval postfx_shader = Shader(arrayOf(\"postfx/vignette\", \"postfx/film_grain\", POSTFX_MAIN_WGSL))\n    postfx_shader.set(\"scene\", scene_texture)\n    postfx_shader.set(\"time\", 0.0)\n\n    // Pass 1: render the particles INTO the intermediate texture.\nval particle_pass = Pass(\"particles\"); particle_pass.addShader(particle_shader)\n    particle_pass.addMesh(mesh)\n    particle_pass.addTarget(intermediate)\n    particle_pass.setClearColor(arrayOf(0.04, 0.05, 0.08, 1.0))\n\n    // Pass 2: sample the intermediate, apply postfx, render to the canvas.\nval postfx_pass = Pass(\"postfx\"); postfx_pass.addShader(postfx_shader)\n    postfx_pass.require(particle_pass)\n\n    app.add(\"shader.particle\", particle_shader)\n    app.add(\"shader.postfx\", postfx_shader)\n    app.add(\"pass.particle\", particle_pass)\n    app.add(\"pass.postfx\", postfx_pass)\n    app.add(\"mesh.main\", mesh)\n\n    for win in windows {\nval target = app.getRenderer().createTarget(win.clone())\n        app.addTarget(win.id(), target)\n    }\n    Ok(())\n}",
